<template><section class="space-y-6"><div><h1 class="text-3xl font-black text-white">Usage Analytics</h1><p class="text-slate-400">Requests, bytes in/out, buckets, and recalculation tools.</p></div><div class="card flex flex-wrap gap-3 p-5"><select v-model="bucket" class="input max-w-xs"><option>minute</option><option>hour</option><option>day</option></select><button class="button-primary" @click="load">Refresh</button><button class="button-secondary" @click="recalculate">Recalculate</button></div><div class="grid gap-4 md:grid-cols-4"><div class="card p-4"><p class="text-slate-400">Requests</p><p class="text-2xl font-black">{{ summary?.total_requests ?? summary?.requests ?? 0 }}</p></div><div class="card p-4"><p class="text-slate-400">Bytes in</p><p class="text-2xl font-black">{{ formatBytes(summary?.bytes_in) }}</p></div><div class="card p-4"><p class="text-slate-400">Bytes out</p><p class="text-2xl font-black">{{ formatBytes(summary?.bytes_out) }}</p></div><div class="card p-4"><p class="text-slate-400">Records</p><p class="text-2xl font-black">{{ summary?.records ?? 0 }}</p></div></div><ChartCard title="Bandwidth in/out" :option="bandwidth" /><ChartCard title="Requests" :option="requests" /></section></template>
<script setup lang="ts">
import { computed, onMounted, ref } from 'vue'; import ChartCard from '@/components/ui/ChartCard.vue'; import { runtimeConfig } from '@/lib/config/env'; import { usageApi } from '@/lib/api/usage'; import { formatBytes } from '@/lib/utils/format'; import type { UsageBucket, UsageSummary } from '@/types';
const bucket = ref<UsageBucket>(runtimeConfig.defaultUsageBucket); const summary = ref<UsageSummary | null>(null); const points = computed(() => summary.value?.points ?? []);
const bandwidth = computed(() => ({ tooltip: {}, legend: {}, xAxis: { type: 'category', data: points.value.map((p) => String(p.bucket ?? p.time ?? '')) }, yAxis: { type: 'value' }, series: [{ name: 'bytes_in', type: 'line', data: points.value.map((p) => Number(p.bytes_in ?? 0)) }, { name: 'bytes_out', type: 'line', data: points.value.map((p) => Number(p.bytes_out ?? 0)) }] }));
const requests = computed(() => ({ tooltip: {}, xAxis: { type: 'category', data: points.value.map((p) => String(p.bucket ?? p.time ?? '')) }, yAxis: { type: 'value' }, series: [{ type: 'bar', data: points.value.map((p) => Number(p.requests ?? 0)) }] }));
async function load() { summary.value = await usageApi.summary({ bucket: bucket.value }).catch(() => null); } async function recalculate() { await usageApi.recalculate(); await load(); } onMounted(load);
</script>
